/* Fast O(1) Unicode property lookup */
static inline uint8_t uprop(uint32_t cp) {
    if (cp > 0x10FFFF) return 0;  /* Out of Unicode range */
    uint16_t page = unicode_page_index[cp >> 8];
    return unicode_props[page][cp & 0xFF];
}

